"use client";

import { useState } from "react";
import { FontAwesomeIcon } from "@fortawesome/react-fontawesome";
import {
  faPencil,
  faTrash,
  faShirt,
} from "@fortawesome/free-solid-svg-icons";
import { togglePlayerActive, deletePlayer } from "@/server/actions/players";
import { PlayerForm } from "./PlayerForm";
import type { FieldingPosition } from "@prisma/client";

const POSITION_LABELS: Record<FieldingPosition, string> = {
  PITCHER:      "P",
  CATCHER:      "C",
  FIRST_BASE:   "1B",
  SECOND_BASE:  "2B",
  THIRD_BASE:   "3B",
  SHORTSTOP:    "SS",
  LEFT_FIELD:   "LF",
  CENTER_FIELD: "CF",
  RIGHT_FIELD:  "RF",
  SHORT_FIELD:  "SF",
  EXTRA_PLAYER: "EP",
  BENCH:        "—",
};

interface Player {
  id: string;
  firstName: string;
  lastName: string;
  jerseyNumber: string | null;
  primaryPosition: FieldingPosition;
  isActive: boolean;
  notes: string | null;
  playerStats: { battingAvg: number | null; ops: number | null } | null;
}

export function PlayerRow({ player }: { player: Player }) {
  const [editing, setEditing] = useState(false);
  const [confirming, setConfirming] = useState(false);

  if (editing) {
    return (
      <tr>
        <td colSpan={6} className="px-4 py-2">
          <PlayerForm player={player} onClose={() => setEditing(false)} />
        </td>
      </tr>
    );
  }

  return (
    <tr
      style={{
        borderBottom: "1px solid var(--color-border-subtle)",
        opacity: player.isActive ? 1 : 0.45,
      }}
    >
      {/* Jersey */}
      <td className="px-4 py-3 text-center">
        <span
          style={{
            fontFamily: "var(--font-mono)",
            fontSize: "0.875rem",
            color: "var(--color-text-muted)",
          }}
        >
          {player.jerseyNumber ? `#${player.jerseyNumber}` : "—"}
        </span>
      </td>

      {/* Name */}
      <td className="px-4 py-3">
        <div className="flex items-center gap-2">
          <span
            style={{
              fontWeight: 600,
              fontSize: "0.9rem",
              color: "var(--color-text-primary)",
              fontFamily: "var(--font-body)",
            }}
          >
            {player.firstName} {player.lastName}
          </span>
          {!player.isActive && (
            <span
              className="rounded px-2 py-0.5 text-xs font-bold"
              style={{
                background: "rgba(255,255,255,0.06)",
                color: "var(--color-text-muted)",
              }}
            >
              INACTIVE
            </span>
          )}
        </div>
        {player.notes && (
          <p className="mt-0.5 text-xs" style={{ color: "var(--color-text-muted)" }}>
            {player.notes}
          </p>
        )}
      </td>

      {/* Position */}
      <td className="px-4 py-3 text-center">
        <span
          className="rounded-full px-3 py-1 text-xs font-bold"
          style={{
            background: "rgba(255,255,255,0.06)",
            color: "var(--color-text-secondary)",
            fontFamily: "var(--font-mono)",
          }}
        >
          {POSITION_LABELS[player.primaryPosition]}
        </span>
      </td>

      {/* Stats */}
      <td className="px-4 py-3 text-center">
        <span
          style={{
            fontFamily: "var(--font-mono)",
            fontSize: "0.875rem",
            color: player.playerStats?.battingAvg
              ? "var(--color-text-brand)"
              : "var(--color-text-muted)",
          }}
        >
          {player.playerStats?.battingAvg
            ? `.${String(Math.round(player.playerStats.battingAvg * 1000)).padStart(3, "0")}`
            : ".000"}
        </span>
      </td>

      <td className="px-4 py-3 text-center">
        <span
          style={{
            fontFamily: "var(--font-mono)",
            fontSize: "0.875rem",
            color: player.playerStats?.ops
              ? "var(--color-text-brand)"
              : "var(--color-text-muted)",
          }}
        >
          {player.playerStats?.ops?.toFixed(3) ?? ".000"}
        </span>
      </td>

      {/* Actions */}
      <td className="px-4 py-3">
        <div className="flex items-center justify-end gap-2">
          {/* Active toggle */}
          <button
            onClick={() => togglePlayerActive(player.id, !player.isActive)}
            title={player.isActive ? "Set inactive" : "Set active"}
            className="rounded-lg p-2 transition-colors hover:bg-white/10"
            style={{
              background: "none",
              border: "none",
              cursor: "pointer",
              color: player.isActive
                ? "var(--color-text-brand)"
                : "var(--color-text-muted)",
            }}
          >
            <FontAwesomeIcon icon={faShirt} style={{ width: 14, height: 14 }} />
          </button>

          {/* Edit */}
          <button
            onClick={() => setEditing(true)}
            title="Edit player"
            className="rounded-lg p-2 transition-colors hover:bg-white/10"
            style={{
              background: "none",
              border: "none",
              cursor: "pointer",
              color: "var(--color-text-muted)",
            }}
          >
            <FontAwesomeIcon icon={faPencil} style={{ width: 14, height: 14 }} />
          </button>

          {/* Delete */}
          {confirming ? (
            <div className="flex items-center gap-1">
              <span className="text-xs" style={{ color: "var(--color-danger-400)" }}>
                Sure?
              </span>
              <button
                onClick={() => deletePlayer(player.id)}
                className="rounded px-2 py-1 text-xs font-bold"
                style={{
                  background: "var(--color-danger-500)",
                  color: "#fff",
                  border: "none",
                  cursor: "pointer",
                }}
              >
                Yes
              </button>
              <button
                onClick={() => setConfirming(false)}
                className="rounded px-2 py-1 text-xs font-bold"
                style={{
                  background: "rgba(255,255,255,0.08)",
                  color: "var(--color-text-muted)",
                  border: "none",
                  cursor: "pointer",
                }}
              >
                No
              </button>
            </div>
          ) : (
            <button
              onClick={() => setConfirming(true)}
              title="Delete player"
              className="rounded-lg p-2 transition-colors hover:bg-white/10"
              style={{
                background: "none",
                border: "none",
                cursor: "pointer",
                color: "var(--color-text-muted)",
              }}
            >
              <FontAwesomeIcon icon={faTrash} style={{ width: 14, height: 14 }} />
            </button>
          )}
        </div>
      </td>
    </tr>
  );
}
